logger = logging.getLogger()
logger.setLevel(os.getenv("LOG_LEVEL", "INFO").upper())

s3 = boto3.client("s3")
sns = boto3.client("sns")

RESULTS_BUCKET = os.getenv("RESULTS_BUCKET", "")
RESULTS_PREFIX = os.getenv("RESULTS_PREFIX", "results/")
SNS_TOPIC_ARN = os.getenv("SNS_TOPIC_ARN", "")

MAX_BYTES_TO_READ = int(os.getenv("MAX_BYTES_TO_READ", str(15 * 1024 * 1024)))
INCLUDE_IMAGE_BYTES_IN_RESULT = os.getenv("INCLUDE_IMAGE_BYTES_IN_RESULT", "false").lower() == "true"


def _now_iso():
    return time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())


def _safe_json(obj):
    return json.dumps(obj, default=str, separators=(",", ":"))


def _publish_sns(subject, message_obj):
    if not SNS_TOPIC_ARN:
        logger.info("SNS_TOPIC_ARN not set; skipping notification. subject=%s message=%s", subject, _safe_json(message_obj))
        return None
    resp = sns.publish(
        TopicArn=SNS_TOPIC_ARN,
        Subject=subject[:100],
        Message=_safe_json(message_obj),
    )
    return resp.get("MessageId")


def _get_s3_object_head(bucket, key):
    return s3.head_object(Bucket=bucket, Key=key)


def _get_s3_object_bytes(bucket, key, max_bytes=MAX_BYTES_TO_READ):
    obj = s3.get_object(Bucket=bucket, Key=key)
    body = obj["Body"].read(max_bytes + 1)
    truncated = len(body) > max_bytes
    if truncated:
        body = body[:max_bytes]
    return body, truncated, obj


def _put_s3_json(bucket, key, data, extra_metadata=None):
    metadata = {}
    if extra_metadata:
        for k, v in extra_metadata.items():
            if v is None:
                continue
            metadata[str(k).lower()[:256]] = str(v)[:2048]
    s3.put_object(
        Bucket=bucket,
        Key=key,
        Body=_safe_json(data).encode("utf-8"),
        ContentType="application/json",
        Metadata=metadata,
    )


def _derive_results_location(src_bucket, src_key):
    dest_bucket = RESULTS_BUCKET or src_bucket
    base = os.path.basename(src_key.rstrip("/"))
    if not base:
        base = "upload"
    stem = base
    result_key = f"{RESULTS_PREFIX.rstrip('/')}/{stem}.{uuid.uuid4().hex}.json"
    return dest_bucket, result_key


def _extract_s3_records(event):
    records = []
    if isinstance(event, dict) and "Records" in event and isinstance(event["Records"], list):
        for r in event["Records"]:
            if r.get("eventSource") == "aws:s3" and "s3" in r:
                b = r["s3"]["bucket"]["name"]
                k = r["s3"]["object"]["key"]
